sed -i "/export default function App() {/a \  useEffect(() => {\n    const handleStorageChange = (e: StorageEvent) => {\n      if (e.key === 'ios_store_apps' && e.newValue) {\n        try { setApps(JSON.parse(e.newValue)); } catch (err) {}\n      }\n      if (e.key === 'ios_store_all_users' && e.newValue) {\n        try { setAllUsers(JSON.parse(e.newValue)); } catch (err) {}\n      }\n    };\n    window.addEventListener('storage', handleStorageChange);\n    return () => window.removeEventListener('storage', handleStorageChange);\n  }, []);" src/App.tsx
